SELECT COUNT(*) FROM LATTES_P_BANCA LPB JOIN LATTES_BANCA LB ON LPB.FK_BANCA = LB.PK JOIN SERVIDOR S ON LPB.FK_SIAPE = S.PK_SIAPE WHERE LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%sociologia%' AND (LOWER(COALESCE(LB.TITULO,'')) LIKE '%aperfe%' OR LOWER(COALESCE(LB.NATUREZA,'')) LIKE '%aperfe%' OR LOWER(COALESCE(LB.TITULO,'')) LIKE '%especializ%' OR LOWER(COALESCE(LB.NATUREZA,'')) LIKE '%especializ%') AND (S.SIGLA_CAMPUS = 'URU' OR LOWER(COALESCE(S.CAMPUS_ATUAL,'')) LIKE '%uruacu%') AND S.GENERO = 'MASCULINO' AND LB.ANO IS NOT NULL AND LB.ANO >= CAST(strftime('%Y', 'now') AS INTEGER) - 4